const cfg = $input.item.json;
const required = [
  'inboxFolderId',
  'processingFolderId',
  'processedFolderId',
  'reviewFolderId',
  'errorFolderId',
  'financialLogSpreadsheetId',
  'financialLogSheetName'
];

const missing = required.filter((key) => {
  const value = cfg[key];
  return value == null || String(value).trim() === '' || String(value).startsWith('REPLACE_WITH_');
});

if (missing.length) {
  throw new Error(`Config placeholders or missing values: ${missing.join(', ')}`);
}

const maxFiles = Number(cfg.maxFilesPerRun ?? 10);
if (!Number.isFinite(maxFiles) || maxFiles < 1 || maxFiles > 100) {
  throw new Error('maxFilesPerRun must be between 1 and 100');
}

const threshold = Number(cfg.confidenceReviewThreshold ?? 0.85);
if (!Number.isFinite(threshold) || threshold <= 0 || threshold >= 1) {
  throw new Error('confidenceReviewThreshold must be between 0 and 1');
}

return [{ json: cfg }];

const items = $input.all().map((i) => i.json || {});
if (!items.length) return [];

items.sort((a, b) => {
  const left = Date.parse(a.createdTime || a.modifiedTime || 0);
  const right = Date.parse(b.createdTime || b.modifiedTime || 0);
  return left - right;
});

return items.map((file) => ({
  json: {
    fileId: file.id,
    fileNameOriginal: file.name || null,
    mimeType: file.mimeType || null,
    createdTime: file.createdTime || null,
    modifiedTime: file.modifiedTime || null
  }
}));

const item = $input.item;

const cfg = $("Config").first().json || {};
const pick = $("Pick Files").item?.json || {};
const moved = $("Move To 10_PROCESSING").item?.json || {};
const downloaded = $("Download File").item?.json || {};

const stableFileId = item.json.fileId || item.json.id || downloaded.id || moved.id || pick.fileId || null;
if (!stableFileId) {
  throw new Error('Unable to resolve Google Drive file ID for downstream processing.');
}

const extractedRaw = typeof item.json.text === 'string' ? item.json.text : '';
let decodedText = extractedRaw
  .replace(/[^\x09\x0A\x0D\x20-\x7E]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

if (!decodedText && item.binary?.data) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  decodedText = buffer
    .toString('utf8')
    .replace(/[^\x09\x0A\x0D\x20-\x7E]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const maxExtractedChars = 12000;
const extractedText = decodedText.slice(0, maxExtractedChars);
const payloadTruncated = decodedText.length > maxExtractedChars;

const originalName = item.json.fileNameOriginal || moved.name || downloaded.name || pick.fileNameOriginal || null;
const mimeType = item.json.mimeType || moved.mimeType || downloaded.mimeType || pick.mimeType || null;

const aiInput = {
  file_id: stableFileId,
  file_name: originalName,
  mime_type: mimeType,
  drive_file_link: `https://drive.google.com/file/d/${stableFileId}/view`,
  payload_truncated: payloadTruncated,
  confidence_review_threshold: Number(cfg.confidenceReviewThreshold ?? 0.85),
  folder_ids: {
    processedFolderId: cfg.processedFolderId,
    reviewFolderId: cfg.reviewFolderId,
    errorFolderId: cfg.errorFolderId
  },
  extracted_text: extractedText,
  extracted_text_chars: extractedText.length
};

return {
  json: {
    fileId: stableFileId,
    fileNameOriginal: originalName,
    mimeType,
    driveFileLink: aiInput.drive_file_link,
    payloadTruncated,
    aiInput,
    chatInput: JSON.stringify(aiInput)
  },
  binary: item.binary
};

const source = $("Prepare AI Input").item.json;
const cfg = $("Config").first().json;

let raw = $input.item.json.output ?? $input.item.json.response ?? $input.item.json.text ?? '';
if (typeof raw !== 'string') raw = JSON.stringify(raw ?? {});
raw = raw.trim();
if (raw.startsWith('```')) {
  const lines = raw.split('\n');
  if (lines[0].startsWith('```')) lines.shift();
  if (lines.length && lines[lines.length - 1].startsWith('```')) lines.pop();
  raw = lines.join('\n').trim();
}

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error(`AI JSON parse failure: ${e.message}`);
}

if (parsed == null || typeof parsed !== 'object' || Array.isArray(parsed)) {
  throw new Error('AI output must be a JSON object');
}

const required = [
  'fileId','fileNameOriginal','fileNameRenamed','documentType','vendor','invoiceId',
  'dateDocument','totalAmount','currency','confidenceScore','reviewStatus','routedFolder',
  'targetFolderId','driveFileLink','notes','eventSummary','timestampProcessed'
];
for (const key of required) {
  if (!(key in parsed)) throw new Error(`Missing AI key: ${key}`);
}

const allowedDocTypes = new Set(['Invoice','Receipt','Bank Statement','Other']);
const allowedReview = new Set(['processed','needs_review','error']);
const allowedRoutes = new Set(['20_PROCESSED','30_REVIEW','99_ERROR']);
if (!allowedDocTypes.has(parsed.documentType)) throw new Error('Invalid documentType');
if (!allowedReview.has(parsed.reviewStatus)) throw new Error('Invalid reviewStatus');
if (!allowedRoutes.has(parsed.routedFolder)) throw new Error('Invalid routedFolder');

const expectedFolder = parsed.routedFolder === '20_PROCESSED'
  ? cfg.processedFolderId
  : parsed.routedFolder === '30_REVIEW'
    ? cfg.reviewFolderId
    : cfg.errorFolderId;
if (String(parsed.targetFolderId) !== String(expectedFolder)) {
  throw new Error('AI targetFolderId does not match routedFolder');
}

const confidence = Number(parsed.confidenceScore);
if (!Number.isFinite(confidence) || confidence < 0 || confidence > 1) {
  throw new Error('Invalid confidenceScore');
}

const total = parsed.totalAmount == null || parsed.totalAmount === '' ? null : Number(parsed.totalAmount);
if (total != null && !Number.isFinite(total)) {
  throw new Error('Invalid totalAmount');
}

return {
  json: {
    ...parsed,
    fileId: parsed.fileId || source.fileId,
    fileNameOriginal: parsed.fileNameOriginal || source.fileNameOriginal,
    driveFileLink: parsed.driveFileLink || source.driveFileLink,
    invoiceId: parsed.invoiceId ?? null,
    totalAmount: total
  }
};

const expected = $("Parse AI Output").item.json.fileId;
const out = $input.item.json || {};
if (!out.id) throw new Error('Rename step did not return file id.');
if (String(out.id) !== String(expected)) {
  throw new Error(`Rename returned unexpected id ${out.id}, expected ${expected}`);
}
return { json: { ...$("Parse AI Output").item.json } };

const appended = $input.item.json || {};

// Ensure append returned row-shaped data from Google Sheets.
const requiredSheetFields = [
  'timestamp_processed',
  'file_name_renamed',
  'file_name_original',
  'document_type',
  'invoice_id'
];
for (const key of requiredSheetFields) {
  if (!(key in appended)) {
    throw new Error(`Append output missing field: ${key}`);
  }
}

// Continue the chain with canonical parsed payload.
return { json: { ...$("Parse AI Output").item.json } };

const expected = $("Parse AI Output").item.json;
const out = $input.item.json || {};
if (!out.id) throw new Error('Move step did not return file id.');
if (String(out.id) !== String(expected.fileId)) {
  throw new Error(`Move returned unexpected id ${out.id}, expected ${expected.fileId}`);
}
return {
  json: {
    ...expected,
    movedFileId: out.id,
    movedFileName: out.name || null
  }
};
